import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient({
  datasources: { db: { url: process.env.DATABASE_URL } },
});

// Retry wrapper for Neon cold-start issues
async function withRetry<T>(fn: () => Promise<T>, retries = 3, delay = 3000): Promise<T> {
  for (let i = 0; i < retries; i++) {
    try {
      return await fn();
    } catch (e: any) {
      if (i < retries - 1 && e?.message?.includes("Can't reach database")) {
        console.log(`  ⏳ DB connection lost, retrying in ${delay/1000}s... (attempt ${i+2}/${retries})`);
        await new Promise(r => setTimeout(r, delay));
      } else throw e;
    }
  }
  throw new Error("Max retries reached");
}

type Q = {
  topic: string;
  year: number;
  questionText: string;
  optionA: string;
  optionB: string;
  optionC: string;
  optionD: string;
  correctOption: "A" | "B" | "C" | "D";
  explanation: string;
  difficulty: "EASY" | "MEDIUM" | "HARD";
};

async function getSubjectId(name: string, level: "JHS" | "SHS"): Promise<string | null> {
  const subject = await withRetry(() => prisma.subject.findFirst({ where: { name, level } }));
  if (!subject) {
    console.log(`  WARNING: Subject "${name}" (${level}) not found in database. Skipping.`);
    return null;
  }
  return subject.id;
}

async function seedQuestions(
  subjectName: string,
  level: "JHS" | "SHS",
  questions: Q[]
) {
  const subjectId = await getSubjectId(subjectName, level);
  if (!subjectId) return 0;

  const examType = level === "JHS" ? "BECE" : "WASSCE";
  let created = 0;

  for (const q of questions) {
    try {
      // Check for duplicate by matching question text + year + subject
      const existing = await withRetry(() => prisma.question.findFirst({
        where: {
          subjectId,
          year: q.year,
          questionText: q.questionText,
        },
      }));
      if (existing) continue;

      await withRetry(() => prisma.question.create({
        data: {
          level,
          examType: examType as any,
          subjectId,
          topic: q.topic,
          year: q.year,
          questionText: q.questionText,
          optionA: q.optionA,
          optionB: q.optionB,
          optionC: q.optionC,
          optionD: q.optionD,
          correctOption: q.correctOption,
          explanation: q.explanation,
          difficulty: q.difficulty as any,
        },
      }));
      created++;
    } catch (err: any) {
      console.log(`  Error inserting question: ${q.questionText.slice(0, 50)}... - ${err.message}`);
    }
  }

  console.log(`  ${subjectName} (${level}): ${created} new questions added (${questions.length - created} skipped as duplicates)`);
  return created;
}

